uint64 _allocpage(void) {
  struct run *ret;
  __enter_sin_cs ret = __sin_alloc_no_lock(); __leave_sin_cs
  if (NULL == ret) {
    __enter_mul_cs ret = __mul_alloc_no_lock(1); __leave_mul_cs
  }
  return (uint64)ret;
}

void _freepage(uint64 pa) {
  uint64 start = (uint64)pa;
  if (start < START_SINGLE) {
    __enter_mul_cs __mul_free_no_lock(start, 1); __leave_mul_cs
  } else {
    __enter_sin_cs __sin_free_no_lock(start); __leave_sin_cs
  }
}

static void *__mul_alloc_no_lock(uint64 n) {
  struct run *pa = multiple.freelist;
  while (NULL != pa) {
    if (pa->npage >= n) {
      struct run *ret = (struct run*)((uint64)pa + PGSIZE * (pa->npage - n));
      if (pa == ret) *pprev = pa->next;
      else { pa->npage -= n; pa = ret; }
      multiple.npage -= n; break;
    }
    pprev = &(pa->next); pa = pa->next;
  }
  return (void*)pa;
}

