pte_t *walk(pagetable_t pagetable, uint64 va, int alloc) {
  for(int level = 2; level > 0; level--) {
    pte_t *pte = &pagetable[PX(level, va)];
    if(*pte & PTE_V) pagetable = (pagetable_t)PTE2PA(*pte);
    else {
      if(!alloc || (pagetable = (pde_t*)allocpage()) == NULL) return NULL;
      memset(pagetable, 0, PGSIZE);
      *pte = PA2PTE(pagetable) | PTE_V;
    }
  }
  return &pagetable[PX(0, va)];
}

int mappages(pagetable_t pagetable, uint64 va, uint64 size, uint64 pa, int perm) {
  uint64 a = PGROUNDDOWN(va), last = PGROUNDDOWN(va + size - 1);
  int usr = perm & PTE_U;
  for(;;){
    if((pte = walk(pagetable, a, 1)) == NULL) return -1;
    if (*pte & PTE_U) { *pte |= PA2PTE(pa) | PTE_V; }
    else { *pte = PA2PTE(pa) | perm | PTE_V; }
    if (usr) pagedup(PGROUNDDOWN(pa));
    if(a == last) break;
    a += PGSIZE; pa += PGSIZE;
  }
  return 0;
}

void unmappages(pagetable_t pagetable, uint64 va, uint64 npages, int flag) {
  for (a = va; a < end; a += PGSIZE) {
    if ((pte = walk(pagetable, a, 0)) == NULL || !(*pte & PTE_V)) continue;
    pa = PTE2PA(*pte);
    if ((flag & VM_FREE) && (!(flag & VM_USER) || pageput(pa) == 0)) freepage((void*)pa);
    *pte = 0;
  }
}

